26         struct Image{
27             public:
28                 std::vector<uint32_t> pixelData;
29                 int width, height;
33                 Image() = delete;
39                 Image(int width, int height){
40                     if(width <= 0 || height <= 0) throw std::runtime_error("Cannot have 0 or Negative Dimension.");
41                     this->width = width;
42                     this->height = height;
43                     pixelData.resize(static_cast<size_t>(width) * height);
44                 }
49                 Image(const Image& src) : width(src.width), height(src.height){
50                     pixelData.resize(static_cast<size_t>(width) * height);
51                     this->pixelData = src.pixelData;
52                 }
53 
61                 static std::shared_ptr<Image> Create(int width, int height, const std::vector<uint32_t>& src = {}){
62 
63                     std::vector<uint32_t> pixDat(width * height, 0x000000FF);
64 
65                     if(!src.empty() && (src.size() == pixDat.size())){
66                         pixDat = src;
67                     }
68 
69                     auto image = std::make_shared<Image>(width,height);
70                     image->pixelData = pixDat;
71 
72                     return image;
73                 }
74 
79                 int getWidth() const { return width;}
80                 int getHeight() const {return height;}
81                 std::vector<uint32_t> getPixelData() const {return pixelData;}
82         };
83 
85         struct BufferedImage : public Image{
91                 BufferedImage(int width, int height) : Image(width, height){}
92                 BufferedImage(const Image& src) : Image(src) {}
93                 BufferedImage() = delete;
94 
95                 uint32_t getValueAt(int x, int y) {
96                     if(x < 0 || y < 0 || x >= width || y >= height) return 0;
97                     int index = x + y * width;
98                     return pixelData[index];
99                 }
100 
101                 void setValueAt(int x, int y, uint32_t value){
102                     if(x < 0 || y < 0 || x >= width || y >= height || value < 0 || value > 0xFFFFFFFF ) return;
103                     int index = x + y * width;
104                     pixelData[index] = value;
105                 }
106 
107                 Color getPixelAt(int x, int y){
108                     return Color::fromRGBA32(getValueAt(x,y));
109                 }
110 
111                 void setPixelAt(int x, int y, Color col){
112                     setValueAt(x,y,col.toRGBA32());
113                 }
114         };
115     }
