148     namespace ShaderDefaults{
149         
150         const std::string SCREEN_VERT_SRC = R"(
151             #version 330 core
152 
156             layout (location = 0) in vec3 aPos;
160             layout (location = 1) in vec4 aColor;     // Mesh class has color at loc 1
164             layout (location = 2) in vec3 aNormal;    // Mesh class has normal at loc 2
168             layout (location = 3) in vec2 aTexCoords; // Mesh class has UV at loc 3
169 
170             out vec2 TexCoords;
171 
172             uniform mat4 u_model;
173             uniform mat4 u_view;
174             uniform mat4 u_projection;
175 
179             void main() {
180                 TexCoords = aTexCoords;
181                 gl_Position = u_projection * u_view * u_model * vec4(aPos, 1.0);
182             }
183         )";
184 
185         const std::string SCREEN_FRAG_SRC = R"(
186             #version 330 core
187 
188             out vec4 FragColor;
189             in vec2 TexCoords;
190 
191             uniform sampler2D screenTexture;
192             uniform int u_applyDeband;
193             uniform int u_frameIndex;
194             uniform float u_debandStrength;
195 
201             float luma(vec3 c){
202                 return dot(c, vec3(0.299, 0.587, 0.114));
203             }
204 
211             float interleavedGradientNoise(vec2 p, float frame){
212                 vec2 jitter = vec2(frame * 0.75487765, frame * 0.56984026);
213                 return fract(52.9829189 * fract(dot(p + jitter, vec2(0.06711056, 0.00583715))));
214             }
215 
222             float triangularNoise(vec2 p, float frame){
223                 float a = interleavedGradientNoise(p + vec2(0.5, 0.25), frame);
224                 float b = interleavedGradientNoise(p + vec2(1.25, 2.75), frame + 17.0);
225                 return a - b;
226             }
227 
231             void main() {
232                 vec4 color = texture(screenTexture, TexCoords);
233 
234                 if(u_applyDeband != 0){
235                     vec2 texelSize = 1.0 / vec2(textureSize(screenTexture, 0));
236                     vec3 rightColor = texture(screenTexture, clamp(TexCoords + vec2(texelSize.x, 0.0), vec2(0.0), vec2(1.0))).rgb;
237                     vec3 upColor = texture(screenTexture, clamp(TexCoords + vec2(0.0, texelSize.y), vec2(0.0), vec2(1.0))).rgb;
238 
239                     float centerLuma = luma(color.rgb);
240                     float gradient = abs(centerLuma - luma(rightColor)) + abs(centerLuma - luma(upColor));
241                     float smoothRegion = 1.0 - smoothstep(0.002, 0.030, gradient);
242 
243                     float frame = mod(float(u_frameIndex), 1024.0);
244                     float noise = triangularNoise(gl_FragCoord.xy, frame);
245                     float strength = (1.0 / 255.0) * max(u_debandStrength, 0.0) * mix(0.35, 1.65, smoothRegion);
246                     color.rgb += vec3(noise * strength);
247                 }
248 
249                 FragColor = vec4(max(color.rgb, vec3(0.0)), color.a);
250             }
251         )";
252 
253     }
